import axios from "axios"

export default class Services{
    constructor(){
        this._service= axios.create({
            baseURL:process.env.REACT_APP_URL,
            withCredentials:true
        })
    }
    firts = () => this._service.get('/menu/first')
    main = () => this._service.get('/menu/main')
    side = () => this._service.get('/menu/side')
    drinks = () => this._service.get('/menu/drinks')
    dessert = () => this._service.get('/menu/dessert')
    request = id => this._service.get(`/menu/${id}`)
    // probar con este para ver si se puede hacer son solo 1
}