import React, { Component } from 'react'
import {Container , Row} from "react-bootstrap"
import Service from '../../service/Dish.service'
import DishCard from './DishCard'
import {Link} from "react-router-dom"

class Main extends Component {
    constructor(props){
        super(props)
        this._service=new Service()
        this.state={
            dishes:[]
        }
    }
    componentDidMount = () => this.updateDishes()

    updateDishes = () =>{
        this._service.main()
        .then(allMains => this.setState({dishes:allMains.data}))
        .catch(err => console.log("error al cargar en el estado los primeros",err))
    }
    render(){
        return(
            <Container>
                <h1>Entrantes</h1>
                <Row>
                    {this.state.dishes.map(dish => <DishCard key={dish._id}{...dish}/> )}
                </Row>
                <Link to="/menu">Vuelta a Menu</Link>
            </Container>
        )
    }
}

export default Main