import React, { Component } from 'react'
import {Switch, Route} from 'react-router-dom'
import Service from './service/Auth.service'
import io from 'socket.io-client'


import Index from './components/pages/Index'
import Menu from './components/pages/Menu';
import Signup from './components/auth/Signup'
import Login from './components/auth/Login'
import Navbar from './components/ui/Navbar'
import First from './components/pages/First'
import Main from './components/pages/Main'
import Side from './components/pages/Side'
import Drinks from './components/pages/Drinks'
import Dessert from './components/pages/Dessert'
import DishDetail from './components/pages/DishDetail'
import Review from './components/orders/Review'
import Edit from './components/orders/EditDish'
import Preparing from './components/orders/Preparing'
import Kitchen from './components/orders/Kitchen'

class App extends Component {
  constructor (){
    super()
    this.state = {loggedInUser:null}
    this._service = new Service()
    this.socket = io('http://localhost:5000')

  }
  setTheUser =user => {
    this.setState({ loggedInUser : user})
  }
  fetchUser = () =>{
    if (this.state.loggedInUser === null) {
      this._service.loggedin()
        .then(theLoggedInUserFromTheServer => this.setState({ loggedInUser: theLoggedInUserFromTheServer.data }))
        .catch(err => {
          this.setState({ loggedInUser: false })
          console.log({ err })
      })
    }
  }


render (){
  this.fetchUser()

  return(
    <>
    <Navbar loggedInUser={this.state.loggedInUser} setUser={this.setTheUser}/>
    <Switch>
    <Route exact path='/' component={Index}/>
    <Route path='/login' render={match => <Login setUser={this.setTheUser}{...match}/>}/>
    <Route path='/signup' render={match => <Signup setUser={this.setTheUser}{...match}/>}/>
    <Route path='/Kitchen' render={()=> <Kitchen loggedInUser={this.state.loggedInUser} socket={this.socket}/>}/>
    <Route exact path='/menu' component={Menu}/>
    <Route path='/menu/first' render={()=> <First loggedInUser={this.state.loggedInUser}/>}/>
    <Route path='/menu/main' render={()=> <Main loggedInUser={this.state.loggedInUser}/>}/>
    <Route path='/menu/side' render={()=> <Side loggedInUser={this.state.loggedInUser}/>}/>
    <Route path='/menu/drinks' render={()=> <Drinks loggedInUser={this.state.loggedInUser}/>}/>
    <Route path='/menu/dessert' render={()=> <Dessert loggedInUser={this.state.loggedInUser}/>}/>
    <Route path="/menu/:category/:id" component={DishDetail} />
    <Route exact path="/order" render={()=> <Review loggedInUser={this.state.loggedInUser} socket={this.socket}/>}/>
    <Route path="/order/preparing" component={Preparing}/>
    <Route path='/edit/:id' component={Edit}/> 
    </Switch>
    </>
  )
}
}

export default App;
